import{_ as o,c as r,o as n,a as e,b as a}from"./app.426dd711.js";const q=JSON.parse('{"title":"3. Sistema Metaf\xF3rico (Metaphorical System)","description":"","frontmatter":{},"headers":[],"relativePath":"practices/metaphorical-system.md"}'),s={name:"practices/metaphorical-system.md"},t=e("h1",{id:"_3-sistema-metaforico-metaphorical-system",tabindex:"-1"},[a("3. Sistema Metaf\xF3rico "),e("em",null,"(Metaphorical System)"),a(),e("a",{class:"header-anchor",href:"#_3-sistema-metaforico-metaphorical-system","aria-hidden":"true"},"#")],-1),i=e("p",null,"A fin de evitar los problemas de comunicaci\xF3n que suelen surgir en la pr\xE1ctica, entre t\xE9cnicos y usuarios, se propone el uso de met\xE1foras, intentando hallar un punto de referencia que permita representar un concepto t\xE9cnico con una situaci\xF3n en com\xFAn con la vida cotidiana y real. Para que una met\xE1fora, cumpla este objetivo, es fundamental: Hacer un paralelismo entre una funcionalidad del sistema y la vida real. Si ese paralelismo (met\xE1fora) no se entiende inmediatamente, se deber\xE1 buscar otra met\xE1fora (una met\xE1fora solo sirve cuando es comprendida de forma inmediata).",-1),c=e("p",null,"Muchas veces, puede ser necesario emplear m\xE1s de una met\xE1fora para explicar una misma caracter\xEDstica del sistema. Incluso, en algunas oportunidades, pueden no encontrarse met\xE1foras que describan con precisi\xF3n toda la caracter\xEDstica que se intenta explicar. Son momentos, en los que se requiere de un gran ingenio y creatividad. Una met\xE1fora es la forma de ser did\xE1cticos para explicar a nuestro receptor, un concepto t\xE9cnico y que \xE9ste, lo comprenda con facilidad. Cada proyecto debe tener una met\xE1fora asociada que nos ofrezca unos criterios para nombrar lo que vayamos haciendo de forma f\xE1cil.",-1),d=e("blockquote",null,[e("p",null,"A la hora de desarrollar c\xF3digo puede surgir el problema de c\xF3mo nombrar los m\xE9todos, funciones, variables, relaciones etc., de un modo coherente y que todos los componentes del equipo lo entiendan. No se debe dejar este tema a la improvisaci\xF3n de cada uno. Los identificadores deber\xE1n ponerse en arreglo a unas ciertas reglas preestablecidas con anterioridad por el grupo. Con esto conseguimos: no perder tiempo valioso de programaci\xF3n en pensar un nombre para un m\xE9todo o similar, y que el resto del equipo no dude sobre el nombre de un m\xE9todo de un paquete desarrollado. Entonces como puede verse ahorramos tiempo por dos v\xEDas: La de creaci\xF3n y la de consulta. Este fundamento ayuda a mantener el c\xF3digo limpio y aumenta su simplicidad.")],-1),l=[t,i,c,d];function m(u,p,f,h,_,b){return n(),r("div",null,l)}const v=o(s,[["render",m]]);export{q as __pageData,v as default};
